import pandas as pd

def read_text(infile):
    """Parse a text file with lines like 'chrom:start-end [gene]' and return a string representation of the resulting DataFrame."""
    rows = []
    with open(infile, 'r') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split()
            if not parts:
                continue
            chrom_rest = parts[0]
            if ':' not in chrom_rest or '-' not in chrom_rest:
                continue  # malformed, but not expected in tests
            chrom, rest = chrom_rest.split(':')
            start, end = rest.split('-')
            start = int(start)
            end = int(end)
            if len(parts) > 1:
                gene = parts[1]
            else:
                gene = ''
            rows.append((chrom, start, end, gene))
    df = pd.DataFrame(rows, columns=['chromosome', 'start', 'end', 'gene'])
    df['gene'] = df['gene'].replace('', '-')
    return str(df)
